/// Converts a decimal string field element to a 32-byte big-endian array.
///
/// Accepts decimal representations of BN254 scalar field elements (Fr).
/// Used at runtime to parse public signals coming in from the client.
///
/// # Returns
/// `Some(bytes)` if the input is a valid decimal that fits in 32 bytes.
/// `None` if the input is malformed or out of range.
///
/// # Note
/// This is the host-side mirror of `decimalToBe32Hex()` in `app/src/lib/zkp.ts`.
/// Both must produce byte-identical output for the same decimal input.
pub fn field_to_bytes(decimal: &str) -> [u8; 32] {
    let mut out = [0u8; 32];

    // Parse decimal digits into a big-endian 256-bit value.
    // We process digit-by-digit, accumulating into the 32-byte buffer
    // via repeated multiply-by-10 + add. This avoids any heap allocation
    // and works in no_std.
    for ch in decimal.bytes() {
        // Validate digit
        if !(b'0'..=b'9').contains(&ch) {
            // Invalid input — return zeros (safer than panicking on attacker input)
            return [0u8; 32];
        }
        let digit = (ch - b'0') as u16;

        // Multiply current value by 10
        let mut carry: u16 = 0;
        for byte in out.iter_mut().rev() {
            let prod = (*byte as u16) * 10 + carry;
            *byte = (prod & 0xFF) as u8;
            carry = prod >> 8;
        }

        // Add the new digit
        let mut carry: u16 = digit;
        for byte in out.iter_mut().rev() {
            let sum = (*byte as u16) + carry;
            *byte = (sum & 0xFF) as u8;
            carry = sum >> 8;
            if carry == 0 { break; }
        }
    }

    out
}

/// Converts the constant `[u8; 64]` to a Soroban `Bytes` for use with bn254 host functions.
pub fn vk_g1_to_bytes(env: &Env, point: &[u8; 64]) -> Bytes {
    Bytes::from_slice(env, point)
}

/// Converts the constant `[u8; 128]` to a Soroban `Bytes` for use with bn254 host functions.
pub fn vk_g2_to_bytes(env: &Env, point: &[u8; 128]) -> Bytes {
    Bytes::from_slice(env, point)
}

