#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn vk_byte_lengths_are_correct() {
        assert_eq!(VK.alpha_1.len(), 64,  "alpha_1 must be 64 bytes (G1)");
        assert_eq!(VK.beta_2.len(),  128, "beta_2 must be 128 bytes (G2)");
        assert_eq!(VK.gamma_2.len(), 128, "gamma_2 must be 128 bytes (G2)");
        assert_eq!(VK.delta_2.len(), 128, "delta_2 must be 128 bytes (G2)");
        assert_eq!(VK.ic.len(), N_PUBLIC + 1, "IC must have length nPublic + 1");
        for (i, ic) in VK.ic.iter().enumerate() {
            assert_eq!(ic.len(), 64, "IC[{}] must be 64 bytes (G1)", i);
        }
    }

    #[test]
    fn field_to_bytes_zero() {
        assert_eq!(field_to_bytes("0"), [0u8; 32]);
    }

    #[test]
    fn field_to_bytes_one() {
        let mut expected = [0u8; 32];
        expected[31] = 1;
        assert_eq!(field_to_bytes("1"), expected);
    }

    #[test]
    fn field_to_bytes_max_32bit() {
        // 4294967295 = 0xFFFFFFFF
        let result = field_to_bytes("4294967295");
        let mut expected = [0u8; 32];
        expected[28..].copy_from_slice(&[0xFF, 0xFF, 0xFF, 0xFF]);
        assert_eq!(result, expected);
    }

    #[test]
    fn field_to_bytes_known_alpha_x() {
        // First 32 bytes of VK.alpha_1 = x coordinate of vk_alpha_1
        // From vkey.json: "12654598567740548349705166083984532613243107033370119541376645559187152863772"
        let expected = &VK.alpha_1[0..32];
        let computed = field_to_bytes("12654598567740548349705166083984532613243107033370119541376645559187152863772");
        assert_eq!(&computed[..], expected, "field_to_bytes must reproduce alpha_1.x exactly");
    }
}